3	type Item = { type: string };
4	
5	type Step = { op: string; items: Item[] };
6	
7	type Scenario = {
8	  customer: { yearsWithMHPCO: number };
9	  steps: Step[];
10	};
11	
12	type StepResult = { premium: number };
13	
14	type ScenarioResult = {
15	  results: StepResult[];
16	};
17	
18	const BASE_PREMIUMS: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	  moonstone: 25,
25	};
26	
27	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
28	const PROCESSING_FEE = 5;
29	
30	const BLOCK_SIZE = 3;
31	const BLOCK_BASE_PREMIUM = 60;
32	
33	const countItemsByType = (items: Item[]): Map<string, number> => {
34	  const counts = new Map<string, number>();
35	  for (const item of items) {
36	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
37	  }
38	  return counts;
39	};
40	
41	const basePremiumForGroup = (type: string, count: number): number =>
42	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];
43	
44	const calculateTotalBasePremium = (items: Item[]): number =>
45	  [...countItemsByType(items)].reduce(
46	    (total, [type, count]) => total + basePremiumForGroup(type, count),
47	    0,
48	  );
49	
50	const quoteStep = (step: Step): StepResult => {
51	  const totalBasePremium = calculateTotalBasePremium(step.items);
52	  const firstInsuranceSurcharge =
53	    totalBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
54	  return {
55	    premium: Math.ceil(
56	      totalBasePremium + firstInsuranceSurcharge + PROCESSING_FEE,
57	    ),
58	  };
59	};
60	
61	export const processScenario = (scenario: Scenario): ScenarioResult => ({
62	  results: scenario.steps.map(quoteStep),
63	});
