const calculateCurseSurcharge = (items: Item[]): number =>
  items
    .filter((item) => item.cursed)
    .reduce(
      (total, item) => total + BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE,
      0,
    );

const quoteStep = (step: Step): StepResult => {
  const totalBasePremium = calculateTotalBasePremium(step.items);
  const firstInsuranceSurcharge =
    totalBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
  const curseSurcharge = calculateCurseSurcharge(step.items);
  return {
    premium: Math.ceil(
      totalBasePremium + curseSurcharge + firstInsuranceSurcharge +
        PROCESSING_FEE,
    ),
  };
};
